// // This module implements a 4-bit synchronous down-counter. The counter decrements its value by one on each rising edge of the clock signal, provided the reset input is low. If the reset signal is asserted, the counter resets its value to zero.
module top_module(
  input clk,
  input reset,
  output reg [3:0] count
);always @(posedge clk) begin
    if (reset) begin
      count <= 0;
    end else begin
      count <= count + 1;
    end
  end

endmodule
